export enum PostAuthIntentType {
  SAVE_LIST = "SAVE_LIST",
  SAVE_LEARNING_OPPORTUNITY = "SAVE_LEARNING_OPPORTUNITY",
  VIEW_LISTS = "VIEW_LISTS",
}

export type PostAuthIntent =
  | {
      type: PostAuthIntentType.SAVE_LIST
      data: {
        listId: string
      }
    }
  | {
      type: PostAuthIntentType.SAVE_LEARNING_OPPORTUNITY
      data: {
        learningOpportunityId: string
      }
    }
  | {
      type: PostAuthIntentType.VIEW_LISTS
    }
