import { Box, Code, Heading, Link, Text } from "@chakra-ui/react";
import NextLink from "next/link";
import ReactMarkdown from "react-markdown";
import remarkBreaks from "remark-breaks";
import remarkGfm from "remark-gfm";
import { isExternal } from "@/utils/string";
type Props = {
  children: string;
};
export function MarkdownText({
  children
}: Props) {
  return <ReactMarkdown remarkPlugins={[remarkBreaks, remarkGfm]} skipHtml={true} components={{
    h1: ({
      ...props
    }) => <Heading marginY={2} as="h1" variant="h1" {...props} />,
    h2: ({
      ...props
    }) => <Heading marginY={2} as="h2" variant="h2" {...props} />,
    h3: ({
      ...props
    }) => <Heading marginY={2} as="h3" variant="h3" {...props} />,
    p: ({
      node,
      children
    }) => {
      const isFirstParagraph = !node?.position?.start?.line || node.position.start.line === 1;
      return <Text marginY={isFirstParagraph ? 0 : 4} as="p" fontSize="md">
              {children}
            </Text>;
    },
    a: ({
      ...props
    }) => <Link as={NextLink} {...props} isExternal={isExternal(props.href)} rel={isExternal(props.href) ? "nofollow noopener noreferrer" : undefined} />,
    ul: ({
      children
    }) => <Text marginLeft={6} as="ul" fontSize="md">
            {children}
          </Text>,
    ol: ({
      children
    }) => <Text marginLeft={6} as="ol" fontSize="md">
            {children}
          </Text>,
    img: () => null,
    // Disable image rendering
    code: ({
      inline,
      children,
      ...props
    }) => inline ? <Code fontSize="sm" {...props}>
              {children}
            </Code> : <Box as="pre" overflowX="auto" padding={4} background="gray.50" borderRadius="md" fontSize="sm" {...props}>
              <Text as="code" whiteSpace="pre" fontSize="sm" display="block" width="full">
                {children}
              </Text>
            </Box>
  }} data-sentry-element="ReactMarkdown" data-sentry-component="MarkdownText" data-sentry-source-file="MarkdownText.tsx">
      {children}
    </ReactMarkdown>;
}