import { Box, HStack, Textarea } from "@chakra-ui/react";
import { useState } from "react";
import SnowdayIcons from "../../ui/icons/SnowdayIcons";
import { MarkdownText } from "../../ui/typography/MarkdownText";
import TextElipsed from "@/ui/typography/TextElipsed";
interface LearningOpportunityNotesProps {
  notes?: string | null;
  editing?: boolean;
  onSave?: (notes: string) => void;
  onCancelEditing?: () => void;
}
export function LearningOpportunityNotes({
  notes,
  editing = false,
  onSave,
  onCancelEditing
}: LearningOpportunityNotesProps) {
  const [editedNotes, setEditedNotes] = useState(notes ?? undefined);
  const handleEditedNotesChange = (event: React.ChangeEvent<HTMLTextAreaElement>) => {
    setEditedNotes(event.target.value);
  };
  const handleCancelEditing = () => {
    setEditedNotes(notes ?? undefined);
    onCancelEditing?.();
  };
  const handleSave = () => {
    if (editedNotes !== undefined && editedNotes.trim() !== notes) {
      onSave?.(editedNotes.trim());
    }
    setEditedNotes(editedNotes?.trim());
  };
  if (editing) {
    return <Box position="relative" width="100%">
        <Textarea value={editedNotes ?? ""} placeholder="Add helpful insights. Note pros/cons or key details&mdash;to guide your own decisions or help others make theirs." onChange={handleEditedNotesChange} resize="none" color="snow.blue-dark" px={3} />
        <HStack position="absolute" right={2} bottom={1} zIndex={500}>
          <SnowdayIcons name="X" color="snow.blue-light-medium" boxSize={6} cursor="pointer" onClick={handleCancelEditing} />
          <SnowdayIcons name="Checkmark" boxSize={6} cursor="pointer" onClick={handleSave} />
        </HStack>
      </Box>;
  }
  if (!notes) {
    return null;
  }
  return <Box backgroundColor="#242F500A" borderRadius={8} padding={3} width="100%" data-sentry-element="Box" data-sentry-component="LearningOpportunityNotes" data-sentry-source-file="LearningOpportunityNotes.tsx">
      <TextElipsed noOfLines={3} color="snow.blue-medium" gradient={false} viewMorePosition="left" data-sentry-element="TextElipsed" data-sentry-source-file="LearningOpportunityNotes.tsx">
        <MarkdownText data-sentry-element="MarkdownText" data-sentry-source-file="LearningOpportunityNotes.tsx">{notes}</MarkdownText>
      </TextElipsed>
    </Box>;
}