import { Flex, Text } from "@chakra-ui/react";
import { useMemo } from "react";
import { Maybe, Season, SessionDateType } from "@/generated/graphql";
import SnowdayIcons from "@/icons/SnowdayIcons";
import { SessionSummary } from "@/types";
import { PredictedBadge } from "@/ui/badges/PredictedBadge";
import { useDevice } from "@/ui/hooks";
import { formatDate, formatDateRange, getSeasonDisplayText } from "@/utils/domain";
interface SessionDatesProps {
  sessions?: Maybe<Maybe<SessionSummary>[]>;
  seasons?: Season[];
}
interface DateMetadata {
  variousStart: boolean;
  variousEnd: boolean;
  start: Date;
  end: Date;
  dateType: SessionDateType;
}
const validateSessionDates = (sessions: Maybe<Maybe<SessionSummary>[]> = []): SessionSummary[] => (sessions ?? []).filter((session: Maybe<SessionSummary>): session is SessionSummary => !!session).filter(({
  dateType,
  startDate,
  endDate
}) => dateType === SessionDateType.Rolling || startDate && endDate);
const variousDates = (sessions: Maybe<SessionSummary>[]): DateMetadata => {
  const [first, ...rest] = validateSessionDates(sessions);
  return [first, ...rest].reverse().reduce((result: DateMetadata, {
    startDate,
    endDate,
    predictedStartDate,
    predictedEndDate
  }) => {
    if (!equalDates(new Date(predictedEndDate ?? endDate), result.end)) {
      result.variousEnd = true;
    }
    if (!equalDates(new Date(predictedStartDate ?? startDate), result.start)) {
      result.variousStart = true;
    }
    result.end = new Date(predictedEndDate ?? endDate);
    result.start = new Date(predictedStartDate ?? startDate);
    return result;
  }, {
    variousStart: false,
    variousEnd: false,
    start: new Date(first.predictedStartDate ?? first.startDate),
    end: new Date(first.predictedEndDate ?? first.endDate),
    dateType: first.dateType
  });
};
const equalDates = (a: Date, b: Date) => a.toLocaleDateString() === b.toLocaleDateString();
const formatSessionDate = (sessions: Maybe<SessionSummary>[], seasons: Season[], isMobile: boolean) => {
  const rolling = sessions.filter(session => session?.dateType === SessionDateType.Rolling).length > 0;
  if (rolling) {
    return "Year Round: Rolling Start";
  }
  const {
    variousStart,
    variousEnd,
    start,
    end,
    dateType
  } = variousDates(sessions);
  const showDay = dateType === SessionDateType.Dates;
  const sameDate = equalDates(start, end);
  const formattedSessionDate = sameDate ? formatDate(start, showDay) : variousStart || variousEnd ? "Various" : formatDateRange(start, end, showDay);
  if (!seasons || seasons.length === 0) {
    return formattedSessionDate;
  }
  const seasonPrefix = createSeasonPrefix(seasons);
  const formattedSessionDateWithSeason = formattedSessionDate === "Various" ? formattedSessionDate : seasonPrefix + formattedSessionDate;

  // Keep things short on smaller displays
  if (formattedSessionDateWithSeason.length > 28 && isMobile) {
    return formattedSessionDate;
  }
  return formattedSessionDateWithSeason;
};
const createSeasonPrefix = (seasons: Season[]) => {
  if (seasons.length >= 3) {
    return "Year Round: ";
  }
  if (seasons.length === 1) {
    return getSeasonDisplayText(seasons[0]) + ": ";
  }
  if (seasons.length === 2 && seasons.includes(Season.Fall) && seasons.includes(Season.Spring)) {
    return "School Year: ";
  }
  return "";
};
export default function SessionDatesComponent({
  sessions = [],
  seasons = []
}: SessionDatesProps) {
  const {
    isMobile
  } = useDevice();
  if (!validateSessionDates(sessions).length) {
    return null;
  }
  const formattedDates = useMemo(() => formatSessionDate(sessions ?? [], seasons, isMobile), [sessions, seasons, isMobile]);
  return <Flex flexDirection="row" alignItems="center" gap={1} data-sentry-element="Flex" data-sentry-component="SessionDatesComponent" data-sentry-source-file="SessionDatesComponent.tsx">
      <SnowdayIcons name="Calendar" boxSize={{
      base: 4,
      md: 5
    }} data-sentry-element="SnowdayIcons" data-sentry-source-file="SessionDatesComponent.tsx" />
      <Text fontSize={{
      base: "15px",
      md: "16px"
    }} lineHeight={{
      base: "15px",
      md: "16px"
    }} data-sentry-element="Text" data-sentry-source-file="SessionDatesComponent.tsx">
        {formattedDates}
      </Text>
      <PredictedBadge predicted={(sessions?.length === 1 && sessions[0]?.predictedStartDate) ?? false} data-sentry-element="PredictedBadge" data-sentry-source-file="SessionDatesComponent.tsx" />
    </Flex>;
}