import { Flex, HStack, ListItem, ResponsiveValue, Text, UnorderedList, useBoolean, VStack } from "@chakra-ui/react";
import { BadgeModalButton, BadgeModalProps } from "./BadgeModal";
import { BottomSheetModal } from "../modals/BottomSheetModal";
import { ExpertsChoiceRating } from "@/generated/graphql";
import HighlyRecommendedBadge from "@/ui/icons/HighlyRecommendedBadge";
import MostRecommendedBadge from "@/ui/icons/MostRecommendedBadge";
interface ExpertsChoiceRatingBadgeProps {
  rating?: ExpertsChoiceRating | null;
  size?: ResponsiveValue<number>;
}
export const ExpertsChoiceRatingBadge = ({
  rating,
  size
}: ExpertsChoiceRatingBadgeProps) => {
  const [open, {
    toggle,
    off
  }] = useBoolean();
  if (rating === undefined || rating === null) {
    return null;
  }
  const renderBadge = () => {
    if (rating === ExpertsChoiceRating.MostRecommended) {
      return <MostRecommendedBadge boxSize={size} />;
    } else if (rating === ExpertsChoiceRating.HighlyRecommended) {
      return <HighlyRecommendedBadge boxSize={size} />;
    } else {
      return null;
    }
  };
  return <>
      <BadgeModalButton onClick={toggle} data-sentry-element="BadgeModalButton" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">{renderBadge()}</BadgeModalButton>
      <ExpertsChoiceRatingModal open={open} onClose={off} data-sentry-element="ExpertsChoiceRatingModal" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx" />
    </>;
};
export const ExpertsChoiceRatingModal = ({
  open,
  onClose
}: BadgeModalProps) => <BottomSheetModal title="Experts' Choice" isOpen={open} onClose={onClose} data-sentry-element="BottomSheetModal" data-sentry-component="ExpertsChoiceRatingModal" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
    <Flex flexDirection="column" gap="1px" maxHeight="100%" overflow="auto" className="scrollbar" data-sentry-element="Flex" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
      <Text fontSize="md" mb={2} data-sentry-element="Text" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
        These badges highlight programs with the strongest reputations among
        experienced education consultants and counselors.
      </Text>
      <Text fontSize="md" data-sentry-element="Text" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
        Snowday does not judge program quality. Instead, we gather ratings from
        a broad network of experts and use trusted consensus-based methods to
        identify where experts show the highest confidence.
      </Text>
      <VStack mt={4} alignItems="flex-start" data-sentry-element="VStack" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
        <HStack alignItems="center" mb={2} data-sentry-element="HStack" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
          <MostRecommendedBadge boxSize={12} data-sentry-element="MostRecommendedBadge" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx" />
          <Text fontWeight="bold" data-sentry-element="Text" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">Most Recommended</Text>
        </HStack>
        <UnorderedList ml={5} data-sentry-element="UnorderedList" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
          <ListItem data-sentry-element="ListItem" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">The highest level of expert confidence (~1%)</ListItem>
          <ListItem data-sentry-element="ListItem" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
            Programs viewed as top-tier, consistently exceptional, and known for
            transformative student outcomes
          </ListItem>
        </UnorderedList>
      </VStack>
      <VStack mt={4} alignItems="flex-start" data-sentry-element="VStack" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
        <HStack alignItems="center" mb={2} data-sentry-element="HStack" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
          <HighlyRecommendedBadge boxSize={12} data-sentry-element="HighlyRecommendedBadge" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx" />
          <Text fontWeight="bold" data-sentry-element="Text" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">Highly Recommended</Text>
        </HStack>
        <UnorderedList ml={5} data-sentry-element="UnorderedList" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
          <ListItem data-sentry-element="ListItem" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">Strong expert confidence (~10%)</ListItem>
          <ListItem data-sentry-element="ListItem" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
            Well-established programs that are widely respected and consistently
            deliver excellent experiences
          </ListItem>
        </UnorderedList>
      </VStack>
      <VStack mt={4} alignItems="flex-start" data-sentry-element="VStack" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
        <HStack alignItems="center" mb={2} data-sentry-element="HStack" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
          <Text fontWeight="bold" data-sentry-element="Text" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">No Badge</Text>
        </HStack>
        <Text fontSize="md" data-sentry-element="Text" data-sentry-source-file="ExpertsChoiceRatingBadge.tsx">
          ~89% of opportunities fall into this category, so a missing badge does
          not indicate poor quality. It simply means the program did not meet
          the high expert-confidence thresholds required — often because experts
          do not know it well enough yet.
        </Text>
      </VStack>
    </Flex>
  </BottomSheetModal>;